+/**
+ * Notification log model for tracking sent notification history.
+ *
+ * Each log entry captures the full context of a notification delivery attempt:
+ * recipient, channel, type, timestamp, and delivery status.
+ */
+
+import type {
+  NotificationChannel,
+  NotificationType,
+  NotificationPriority,
+  NotificationStatus,
+} from './notification.js';
+
+/**
+ * A persisted record of a notification delivery attempt.
+ */
+export interface NotificationLog {
+  id: string;
+  /** The original notification ID from NotificationService */
+  notificationId: string;
+  /** Target recipient (email, user ID, webhook URL, etc.) */
+  recipient: string;
+  /** Delivery channel used */
+  channel: NotificationChannel;
+  /** Notification category */
+  type: NotificationType;
+  /** Delivery priority */
+  priority: NotificationPriority;
+  /** Notification subject */
+  subject: string;
+  /** Final delivery status */
+  status: NotificationStatus;
+  /** When the notification was sent/attempted */
+  sentAt: Date;
+  /** When this log entry was created */
+  createdAt: Date;
+  /** Optional metadata from the notification */
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * Query filters for searching notification history.
+ */
+export interface NotificationLogQuery {
+  recipient?: string;
+  channel?: NotificationChannel;
+  type?: NotificationType;
+  status?: NotificationStatus;
+  startDate?: Date;
+  endDate?: Date;
+}

