/**
 * Notification log model for tracking sent notification history.
 *
 * Each log entry captures the full context of a notification delivery attempt:
 * recipient, channel, type, timestamp, and delivery status.
 */

import type {
  NotificationChannel,
  NotificationType,
  NotificationPriority,
  NotificationStatus,
} from './notification.js';

/**
 * A persisted record of a notification delivery attempt.
 */
export interface NotificationLog {
  id: string;
  /** The original notification ID from NotificationService */
  notificationId: string;
  /** Target recipient (email, user ID, webhook URL, etc.) */
  recipient: string;
  /** Delivery channel used */
  channel: NotificationChannel;
  /** Notification category */
  type: NotificationType;
  /** Delivery priority */
  priority: NotificationPriority;
  /** Notification subject */
  subject: string;
  /** Final delivery status */
  status: NotificationStatus;
  /** When the notification was sent/attempted */
  sentAt: Date;
  /** When this log entry was created */
  createdAt: Date;
  /** Optional metadata from the notification */
  metadata?: Record<string, unknown>;
}

/**
 * Query filters for searching notification history.
 */
export interface NotificationLogQuery {
  recipient?: string;
  channel?: NotificationChannel;
  type?: NotificationType;
  status?: NotificationStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type {
  NotificationChannel,
  NotificationType,
  NotificationStatus,
} from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    const log: NotificationLog = {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      priority: record['priority'] as string as NotificationLog['priority'],
      subject: record['subject'] as string,
      status: record['status'] as NotificationStatus,
      sentAt: new Date(record['sentAt'] as string),
      createdAt: new Date(record['createdAt'] as string),
    };
    if (record['metadata']) {
      log.metadata = JSON.parse(record['metadata'] as string) as Record<string, unknown>;
    }
    return log;
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      priority: entity.priority,
      subject: entity.subject,
      status: entity.status,
      sentAt: entity.sentAt.toISOString(),
      createdAt: entity.createdAt.toISOString(),
    };
    if (entity.metadata) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }
    return record;
  }

  /**
   * Find all logs for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find all logs for a specific notification type.
   */
  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  /**
   * Find all logs for a specific channel.
   */
  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  /**
   * Find all logs with a specific status.
   */
  findByStatus(status: NotificationStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  /**
   * Find all logs within a date range (inclusive).
   */
  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.sentAt >= startDate && log.sentAt <= endDate,
    );
  }
}

/**
 * Service for tracking and querying notification history.
 *
 * Logs every notification delivery attempt via the NotificationLogRepository
 * and provides query methods for filtering history by recipient, type,
 * channel, status, and date range.
 *
 * Integrated with NotificationService via setter injection — the notification
 * service calls logNotification() after every send() attempt.
 */

import type { Notification } from '../models/notification.js';
import type { NotificationLog, NotificationLogQuery } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';
import type { PaginationResult } from '../utils/pagination.js';
import { paginate } from '../utils/pagination.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a notification delivery attempt. Called by NotificationService
   * after every send().
   */
  logNotification(notification: Notification): NotificationLog {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      priority: notification.priority,
      subject: notification.subject,
      status: notification.status,
      sentAt: notification.sentAt,
      createdAt: new Date(),
      metadata: notification.metadata,
    };

    this.repository.save(log);
    this.logger.info(`Logged notification ${notification.id} (${notification.status}) for ${notification.recipient}`);
    return log;
  }

  /**
   * Query notification history with flexible filters.
   * All filters are AND-combined.
   */
  query(filters: NotificationLogQuery): NotificationLog[] {
    let results = this.repository.findAll();

    if (filters.recipient) {
      results = results.filter((log) => log.recipient === filters.recipient);
    }
    if (filters.channel) {
      results = results.filter((log) => log.channel === filters.channel);
    }
    if (filters.type) {
      results = results.filter((log) => log.type === filters.type);
    }
    if (filters.status) {
      results = results.filter((log) => log.status === filters.status);
    }
    if (filters.startDate) {
      results = results.filter((log) => log.sentAt >= filters.startDate!);
    }
    if (filters.endDate) {
      results = results.filter((log) => log.sentAt <= filters.endDate!);
    }

    return results;
  }

  /**
   * Query with pagination support.
   */
  queryPaginated(
    filters: NotificationLogQuery,
    page: number,
    pageSize: number,
  ): PaginationResult<NotificationLog> {
    const results = this.query(filters);
    return paginate(results, page, pageSize);
  }

  /**
   * Get all history for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all history for a specific notification type.
   */
  getByType(type: Notification['type']): NotificationLog[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all history for a specific channel.
   */
  getByChannel(channel: Notification['channel']): NotificationLog[] {
    return this.repository.findByChannel(channel);
  }

  /**
   * Get all history within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Get a specific log entry by ID.
   */
  getById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get the total number of log entries.
   */
  getCount(): number {
    return this.repository.count();
  }
}

