import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
    resetNotificationIdCounter();
  });

  describe('logNotification', () => {
    it('should log a sent notification', () => {
      const log = historyService.logNotification({
        id: 'notif-0001',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'email',
        type: 'order-confirmation',
        priority: 'normal',
        status: 'sent',
        sentAt: new Date('2026-01-15T10:00:00Z'),
      });

      expect(log.id).toBe('log-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order-confirmation');
      expect(log.priority).toBe('normal');
      expect(log.subject).toBe('Order Confirmation');
      expect(log.status).toBe('sent');
      expect(log.sentAt).toEqual(new Date('2026-01-15T10:00:00Z'));
    });

    it('should log a failed notification', () => {
      const log = historyService.logNotification({
        id: 'notif-0001',
        recipient: 'bob@example.com',
        subject: 'Alert',
        body: 'Something happened.',
        channel: 'sms',
        type: 'system-alert',
        priority: 'high',
        status: 'failed',
        sentAt: new Date('2026-01-15T10:00:00Z'),
      });

      expect(log.status).toBe('failed');
      expect(log.channel).toBe('sms');
    });

    it('should log a suppressed notification', () => {
      const log = historyService.logNotification({
        id: 'notif-0001',
        recipient: 'carol@example.com',
        subject: 'Update',
        body: 'Profile updated.',
        channel: 'email',
        type: 'user-profile-update',
        priority: 'low',
        status: 'suppressed',
        metadata: { suppressedByPreferences: true },
        sentAt: new Date('2026-01-15T10:00:00Z'),
      });

      expect(log.status).toBe('suppressed');
      expect(log.metadata).toEqual({ suppressedByPreferences: true });
    });

    it('should generate sequential log IDs', () => {
      const log1 = historyService.logNotification({
        id: 'notif-0001',
        recipient: 'a@example.com',
        subject: 'S',
        body: 'B',
        channel: 'email',
        type: 'system-alert',
        priority: 'normal',
        status: 'sent',
        sentAt: new Date(),
      });
      const log2 = historyService.logNotification({
        id: 'notif-0002',
        recipient: 'b@example.com',
        subject: 'S',
        body: 'B',
        channel: 'email',
        type: 'system-alert',
        priority: 'normal',
        status: 'sent',
        sentAt: new Date(),
      });

      expect(log1.id).toBe('log-0001');
      expect(log2.id).toBe('log-0002');
    });

    it('should persist logs in the repository', () => {
      historyService.logNotification({
        id: 'notif-0001',
        recipient: 'a@example.com',
        subject: 'S',
        body: 'B',
        channel: 'email',
        type: 'system-alert',
        priority: 'normal',
        status: 'sent',
        sentAt: new Date(),
      });

      expect(historyService.getCount()).toBe(1);
      expect(historyService.getById('log-0001')).toBeDefined();
    });
  });

  describe('query', () => {
    beforeEach(() => {
      // Seed with varied notification logs
      historyService.logNotification({
        id: 'notif-0001',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order.',
        channel: 'email',
        type: 'order-confirmation',
        priority: 'normal',
        status: 'sent',
        sentAt: new Date('2026-01-10T10:00:00Z'),
      });
      historyService.logNotification({
        id: 'notif-0002',
        recipient: 'alice@example.com',
        subject: 'Order Update',
        body: 'Status changed.',
        channel: 'email',
        type: 'order-status-update',
        priority: 'normal',
        status: 'sent',
        sentAt: new Date('2026-01-15T10:00:00Z'),
      });
      historyService.logNotification({
        id: 'notif-0003',
        recipient: 'bob@example.com',
        subject: 'Welcome',
        body: 'Welcome aboard.',
        channel: 'email',
        type: 'user-welcome',
        priority: 'normal',
        status: 'sent',
        sentAt: new Date('2026-01-20T10:00:00Z'),
      });
      historyService.logNotification({
        id: 'notif-0004',
        recipient: 'alice@example.com',
        subject: 'Webhook Event',
        body: 'Event data.',
        channel: 'webhook',
        type: 'system-alert',
        priority: 'high',
        status: 'failed',
        sentAt: new Date('2026-01-25T10:00:00Z'),
      });
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(3);
      results.forEach((log) => expect(log.recipient).toBe('alice@example.com'));
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'order-confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order-confirmation');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-01-12T00:00:00Z'),
        endDate: new Date('2026-01-22T00:00:00Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        channel: 'email',
      });
      expect(results).toHaveLength(2);
    });

    it('should return all logs when no filters provided', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(4);
    });

    it('should return empty array when no matches', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('queryPaginated', () => {
    beforeEach(() => {
      for (let i = 0; i < 15; i++) {
        historyService.logNotification({
          id: `notif-${String(i + 1).padStart(4, '0')}`,
          recipient: 'alice@example.com',
          subject: `Notification ${i + 1}`,
          body: 'Body',
          channel: 'email',
          type: 'system-alert',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date(`2026-01-${String(i + 1).padStart(2, '0')}T10:00:00Z`),
        });
      }
    });

    it('should paginate results', () => {
      const result = historyService.queryPaginated({}, 1, 5);
      expect(result.items).toHaveLength(5);
      expect(result.totalItems).toBe(15);
      expect(result.totalPages).toBe(3);
      expect(result.hasNext).toBe(true);
      expect(result.hasPrevious).toBe(false);
    });

    it('should return last page correctly', () => {
      const result = historyService.queryPaginated({}, 3, 5);
      expect(result.items).toHaveLength(5);
      expect(result.hasNext).toBe(false);
      expect(result.hasPrevious).toBe(true);
    });

    it('should paginate filtered results', () => {
      const result = historyService.queryPaginated(
        { startDate: new Date('2026-01-05T00:00:00Z'), endDate: new Date('2026-01-10T00:00:00Z') },
        1,
        3,
      );
      expect(result.totalItems).toBe(6);
      expect(result.items).toHaveLength(3);
    });
  });

  describe('convenience query methods', () => {
    beforeEach(() => {
      historyService.logNotification({
        id: 'notif-0001',
        recipient: 'alice@example.com',
        subject: 'S',
        body: 'B',
        channel: 'email',
        type: 'order-confirmation',
        priority: 'normal',
        status: 'sent',
        sentAt: new Date('2026-01-10T10:00:00Z'),
      });
      historyService.logNotification({
        id: 'notif-0002',
        recipient: 'bob@example.com',
        subject: 'S',
        body: 'B',
        channel: 'webhook',
        type: 'system-alert',
        priority: 'high',
        status: 'failed',
        sentAt: new Date('2026-01-20T10:00:00Z'),
      });
    });

    it('getByRecipient should return logs for that recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('bob@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('nobody@example.com')).toHaveLength(0);
    });

    it('getByType should return logs for that type', () => {
